Choose an isolation strategy based on security requirements, compliance needs, and operational complexity:

 Strategy
 Isolation Level
 Use Case

 Separate Databases
 Highest
 Regulated industries, enterprise clients

 Separate Schemas
 High
 Balance of isolation and manageability

 Shared Tables (Row-Level)
 Medium
 Cost-sensitive, high tenant count

 Hybrid
 Variable
 Different tiers for different customers

 Row-Level Security Implementation (PostgreSQL)

 -- Enable RLS on tenant tables
 ALTER TABLE orders ENABLE ROW LEVEL SECURITY ;
 ALTER TABLE customers ENABLE ROW LEVEL SECURITY ;

 -- Create policy that restricts access to current tenant
 CREATE POLICY tenant_isolation_policy ON orders
 FOR ALL
 USING ( tenant_id = current_setting ( 'app.current_tenant' ):: uuid );

 CREATE POLICY tenant_isolation_policy ON customers
 FOR ALL
 USING ( tenant_id = current_setting ( 'app.current_tenant' ):: uuid );

 -- Force RLS for table owners too (important!)
 ALTER TABLE orders FORCE ROW LEVEL SECURITY ;
 ALTER TABLE customers FORCE ROW LEVEL SECURITY ;

 Application-Level Enforcement (Python/SQLAlchemy)

 from sqlalchemy import event , Column , String
 from sqlalchemy.orm import Session , Query
 from sqlalchemy.ext.declarative import declared_attr
 from contextlib import contextmanager

 class TenantMixin :
 """Mixin that adds tenant_id to all models."""

 @declared_attr
 def tenant_id ( cls ):
 return Column ( String ( 36 ), nullable = False , index = True )

 class TenantAwareSession ( Session ):
 """Session that automatically filters by tenant."""

 def __init__ ( self , * args , tenant_id : str = None , ** kwargs ):
 super () . __init__ ( * args , ** kwargs )
 self . _tenant_id = tenant_id

 @property
 def tenant_id ( self ):
 if not self . _tenant_id :
 raise SecurityException ( "Tenant ID not set on session" )
 return self . _tenant_id

 # Automatically add tenant filter to all queries
 @event . listens_for ( Query , "before_compile" , retval = True )
 def add_tenant_filter ( query ):
 tenant_id = current_tenant . get ()
 if not tenant_id :
 raise SecurityException ( "No tenant context for query" )

 for desc in query . column_descriptions :
 entity = desc . get ( 'entity' )
 if entity and hasattr ( entity , 'tenant_id' ):
 query = query . filter ( entity . tenant_id == tenant_id . tenant_id )

 return query

 # Automatically set tenant_id on insert
 @event . listens_for ( TenantMixin , "before_insert" , propagate = True )
 def set_tenant_on_insert ( mapper , connection , target ):
 ctx = current_tenant . get ()
 if not ctx :
 raise SecurityException ( "Cannot insert without tenant context" )
 target . tenant_id = ctx . tenant_id

 # Secure session factory
 @contextmanager
 def tenant_session ( tenant_id : str ):
 """Create a tenant-scoped database session."""
 session = TenantAwareSession ( bind = engine , tenant_id = tenant_id )

 # Set PostgreSQL RLS context
 session . execute ( f "SELECT set_config('app.current_tenant', :tenant_id, true);" )

 try :
 yield session
 session . commit ()
 except Exception :
 session . rollback ()
 raise
 finally :
 session . close ()

Always validate that requested resources belong to the current tenant.

Use composite keys (tenant_id + resource_id) for all lookups.

Implement authorization checks at the data access layer, not just API layer.

Avoid exposing sequential or guessable IDs.

 Bad example: Direct object reference without tenant validation

 # Dangerous: Only checks resource_id, not tenant ownership
 @app . get ( "/api/documents/ {document_id} " )
 async def get_document ( document_id : str ):
 doc = db . query ( Document ) . filter ( Document . id == document_id ) . first ()
 if not doc :
 raise HTTPException ( 404 )
 return doc # Could return another tenant's document!

 Good example: Tenant-scoped resource access

 from uuid import UUID
 from typing import TypeVar , Generic , Type

 T = TypeVar ( 'T' )

 class TenantScopedRepository ( Generic [ T ]):
 """Repository that enforces tenant isolation on all operations."""

 def __init__ ( self , model : Type [ T ], session : Session ):
 self . model = model
 self . session = session

 @property
 def tenant_id ( self ) -> str :
 ctx = current_tenant . get ()
 if not ctx :
 raise SecurityException ( "Tenant context required" )
 return ctx . tenant_id

 def get_by_id ( self , resource_id : UUID ) -> Optional [ T ]:
 """Get resource only if it belongs to current tenant."""
 return self . session . query ( self . model ) . filter (
 self . model . id == resource_id ,
 self . model . tenant_id == self . tenant_id # Always include tenant check
 ) . first ()

 def list_all ( self , limit : int = 100 , offset : int = 0 ) -> list [ T ]:
 """List resources for current tenant only."""
 return self . session . query ( self . model ) . filter (
 self . model . tenant_id == self . tenant_id
 ) . limit ( limit ) . offset ( offset ) . all ()

 def create ( self , ** kwargs ) -> T :
 """Create resource with tenant_id automatically set."""
 if 'tenant_id' in kwargs and kwargs [ 'tenant_id' ] != self . tenant_id :
 raise SecurityException ( "Cannot create resource for different tenant" )

 kwargs [ 'tenant_id' ] = self . tenant_id
 instance = self . model ( ** kwargs )
 self . session . add ( instance )
 return instance

 def delete ( self , resource_id : UUID ) -> bool :
 """Delete resource only if it belongs to current tenant."""
 result = self . session . query ( self . model ) . filter (
 self . model . id == resource_id ,
 self . model . tenant_id == self . tenant_id
 ) . delete ()
 return result > 0

 # Usage
 @app . get ( "/api/documents/ {document_id} " )
 @require_tenant
 async def get_document ( document_id : UUID , db : Session = Depends ( get_db )):
 repo = TenantScopedRepository ( Document , db )
 doc = repo . get_by_id ( document_id )
 if not doc :
 raise HTTPException ( 404 , "Document not found" ) # Don't reveal if it exists for other tenant
 return doc

Network segmentation is the core of multi-layer defense in depth for modern services. Segmentation slow down an attacker if he cannot implement attacks such as:

SQL-injections, see SQL Injection Prevention Cheat Sheet ;

compromise of workstations of employees with elevated privileges;

compromise of another server in the perimeter of the organization;

compromise of the target service through the compromise of the LDAP directory, DNS server, and other corporate services and sites published on the Internet.

The main goal of this cheat sheet is to show the basics of network segmentation to effectively counter attacks by building a secure and maximally isolated service network architecture.

Segmentation will avoid the following situations:

executing arbitrary commands on a public web server (NginX, Apache, Internet Information Service) prevents an attacker from gaining direct access to the database;

having unauthorized access to the database server, an attacker cannot access CnC on the Internet.

Schematic symbols;

Three-layer network architecture;

Interservice interaction;

Network security policy;

Useful links.

By default, developed information systems should consist of at least three components ( security zones ):

 FRONTEND ;

 MIDDLEWARE ;

 BACKEND .

FRONTEND - A frontend is a set of segments with the following network elements:

balancer;

application layer firewall;

web server;

web cache.

MIDDLEWARE - a set of segments to accommodate the following network elements:

web applications that implement the logic of the information system (processing requests from clients, other services of the company and external services; execution of requests);

authorization services;

analytics services;

message queues;

stream processing platform.

BACKEND - a set of network segments to accommodate the following network elements:

SQL database;

LDAP directory (Domain controller);

storage of cryptographic keys;

file server.

The following example shows an organization's local network. The organization is called "Сontoso".

The edge firewall contains 2 VLANs of FRONTEND security zone:

 DMZ Inbound - a segment for hosting services and applications accessible from the Internet, they must be protected by WAF;

 DMZ Outgoing - a segment for hosting services that are inaccessible from the Internet, but have access to external networks (the firewall does not contain any rules for allowing traffic from external networks).

The internal firewall contains 4 VLANs:

 MIDDLEWARE security zone contains only one VLAN with name APPLICATIONS - a segment designed to host information system applications that interact with each other (interservice communication) and interact with other services;

 BACKEND security zone contains:

 DATABASES - a segment designed to delimit various databases of an automated system;

 AD SERVICES - segment designed to host various Active Directory services, in the example only one server with a domain controller Contoso.com is shown;

 LOGS - segment, designed to host servers with logs, servers centrally store application logs of an automated system.

The organization must define a "paper" policy that describes firewall rules and basic allowed network access.
This policy is at least useful:

network administrators;

security representatives;

IT auditors;

architects of information systems and software;

developers;

IT administrators.

It is convenient when the policy is described by similar images. The information is presented as concisely and simply as possible.

Examples in the network policy will help colleagues quickly understand what access is potentially allowed and can be requested.

 Permissions for CI/CD &para;

The network security policy may define, for example, the basic permissions allowed for the software development system. Let's look at an example of what such a policy might look like:

 Secure logging &para;

It is important that in the event of a compromise of any information system, its logs are not subsequently modified by an attacker. To do this, you can do the following: copy the logs to a separate server, for example, using the syslog protocol, which does not allow an attacker to modify the logs, syslog only allows you to add new events to the logs.
The network security policy for this activity looks like this:

In this example, we are also talking about application logs that may contain security events, as well as potentially important events that may indicate an attack.

 Permissions for monitoring systems &para;

Suppose a company uses Zabbix as an IT monitoring system. In this case, the policy might look like this:

If we’re already discussing process signals that terminate applications, let’s make sure we’re shutting them down properly and gracefully without disrupting users.

When a Node.js application receives an interrupt signal, also known as
SIGINT
, or
CTRL+C
, it will cause an abrupt process kill, unless any event handlers were set of course to handle it in a different behavior. This means that connected clients to a web application will be immediately disconnected. Now, imagine hundreds of Node.js web containers orchestrated by Kubernetes, going up and down as needs arise to scale or manage errors. Not the greatest user experience.

You can easily simulate this problem. Here’s a stock Fastify web application example, with an inherent delayed response of 60 seconds for an endpoint:

fastify.get('/delayed', async (request, reply) => {
 const SECONDS_DELAY = 60000
 await new Promise(resolve => {
 setTimeout(() => resolve(), SECONDS_DELAY)
 })
 return { hello: 'delayed world' }
})

const start = async () => {
 try {
 await fastify.listen(PORT, HOST)
 console.log(`*^!@4=> Process id: ${process.pid}`)
 } catch (err) {
 fastify.log.error(err)
 process.exit(1)
 }
}

start()

Run this application and once it’s running send a simple HTTP request to this endpoint:

$ time curl https://localhost:3000/delayed

Hit
CTRL+C
 in the running Node.js console window and you’ll see that the curl request exited abruptly. This simulates the same experience your users would receive when containers tear down.

To provide a better experience, we can do the following:

Set an event handler for the various termination signals like
SIGINT
 and
SIGTERM
.

The handler waits for clean up operations like database connections, ongoing HTTP requests and others.

The handler then terminates the Node.js process.

Specifically with Fastify, we can have our handler call on fastify.close() which returns a promise that we will await, and Fastify will also take care to respond to every new connection with the HTTP status code 503 to signal that the application is unavailable.

Let’s add our event handler:

async function closeGracefully(signal) {
 console.log(`*^!@4=> Received signal to terminate: ${signal}`)

 await fastify.close()
 // await db.close() if we have a db connection in this app
 // await other things we should cleanup nicely
 process.exit()
}
process.on('SIGINT', closeGracefully)
process.on('SIGTERM', closeGracefully)

Admittedly, this is more of a generic web application concern than Dockerfile related, but is even more important in orchestrated environments.

Use flat Promise chains &para;

Asynchronous callback functions are one of the strongest features of Node.js. However, increasing layers of nesting within callback functions can become a problem. Any multistage process can become nested 10 or more levels deep. This problem is referred to as a "Pyramid of Doom" or "Callback Hell". In such code, the errors and results get lost within the callback. Promises are a good way to write asynchronous code without getting into nested pyramids. Promises provide top-down execution while being asynchronous by delivering errors and results to next
.then
 function.

Another advantage of Promises is the way Promises handle errors. If an error occurs in a Promise class, it skips over the
.then
 functions and invokes the first
.catch
 function it finds. This way Promises provide a higher assurance of capturing and handling errors. As a principle, you can make all your asynchronous code (apart from emitters) return promises. It should be noted that Promise calls can also become a pyramid. In order to completely stay away from "Callback Hell", flat Promise chains should be used. If the module you are using does not support Promises, you can convert base object to a Promise by using
Promise.promisifyAll()
 function.

The following code snippet is an example of "Callback Hell":

 function func1 ( name , callback ) {
 // operations that takes a bit of time and then calls the callback
 }
 function func2 ( name , callback ) {
 // operations that takes a bit of time and then calls the callback
 }
 function func3 ( name , callback ) {
 // operations that takes a bit of time and then calls the callback
 }
 function func4 ( name , callback ) {
 // operations that takes a bit of time and then calls the callback
 }

 func1 ( "input1" , function ( err , result1 ){
 if ( err ){
 // error operations
 }
 else {
 //some operations
 func2 ( "input2" , function ( err , result2 ){
 if ( err ){
 //error operations
 }
 else {
 //some operations
 func3 ( "input3" , function ( err , result3 ){
 if ( err ){
 //error operations
 }
 else {
 // some operations
 func4 ( "input 4" , function ( err , result4 ){
 if ( err ){
 // error operations
 }
 else {
 // some operations
 }
 });
 }
 });
 }
 });
 }
 });

The above code can be securely written as follows using a flat Promise chain:

 function func1 ( name ) {
 // operations that takes a bit of time and then resolves the promise
 }
 function func2 ( name ) {
 // operations that takes a bit of time and then resolves the promise
 }
 function func3 ( name ) {
 // operations that takes a bit of time and then resolves the promise
 }
 function func4 ( name ) {
 // operations that takes a bit of time and then resolves the promise
 }

 func1 ( "input1" )
 . then ( function ( result ){
 return func2 ( "input2" );
 })
 . then ( function ( result ){
 return func3 ( "input3" );
 })
 . then ( function ( result ){
 return func4 ( "input4" );
 })
 . catch ( function ( error ) {
 // error operations
 });

And using async/await:

 async function func1 ( name ) {
 // operations that takes a bit of time and then resolves the promise
 }
 async function func2 ( name ) {
 // operations that takes a bit of time and then resolves the promise
 }
 async function func3 ( name ) {
 // operations that takes a bit of time and then resolves the promise
 }
 async function func4 ( name ) {
 // operations that takes a bit of time and then resolves the promise
 }

 ( async () => {
 try {
 let res1 = await func1 ( "input1" );
 let res2 = await func2 ( "input2" );
 let res3 = await func3 ( "input2" );
 let res4 = await func4 ( "input2" );
 } catch ( err ) {
 // error operations
 }
 })();

 Set request size limits &para;

Buffering and parsing of request bodies can be a resource intensive task. If there is no limit on the size of requests, attackers can send requests with large request bodies that can exhaust server memory and/or fill disk space. You can limit the request body size for all requests using raw-body .

 const contentType = require ( 'content-type' )
 const express = require ( 'express' )
 const getRawBody = require ( 'raw-body' )

 const app = express ()

 app . use ( function ( req , res , next ) {
 if ( ! [ 'POST' , 'PUT' , 'DELETE' ]. includes ( req . method )) {
 next ()
 return
 }

 getRawBody ( req , {
 length : req . headers [ 'content-length' ],
 limit : '1kb' ,
 encoding : contentType . parse ( req ). parameters . charset
 }, function ( err , string ) {
 if ( err ) return next ( err )
 req . text = string
 next ()
 })
 })

However, fixing a request size limit for all requests may not be the correct behavior, since some requests may have a large payload in the request body, such as when uploading a file. Also, input with a JSON type is more dangerous than a multipart input, since parsing JSON is a blocking operation. Therefore, you should set request size limits for different content types. You can accomplish this very easily with express middleware as follows:

 app . use ( express . urlencoded ({ extended : true , limit : "1kb" }));
 app . use ( express . json ({ limit : "1kb" }));

It should be noted that attackers can change the
Content-Type
 header of the request and bypass request size limits. Therefore, before processing the request, data contained in the request should be validated against the content type stated in the request headers. If content type validation for each request affects the performance severely, you can only validate specific content types or request larger than a predetermined size.

 Do not block the event loop &para;

Node.js is very different from common application platforms that use threads. Node.js has a single-thread event-driven architecture. By means of this architecture, throughput becomes high and the programming model becomes simpler. Node.js is implemented around a non-blocking I/O event loop. With this event loop, there is no waiting on I/O or context switching. The event loop looks for events and dispatches them to handler functions. Because of this, when CPU intensive JavaScript operations are executed, the event loop waits for them to finish. This is why such operations are called "blocking". To overcome this problem, Node.js allows assigning callbacks to IO-blocked events. This way, the main application is not blocked and callbacks run asynchronously. Therefore, as a general principle, all blocking operations should be done asynchronously so that the event loop is not blocked.

Even if you perform blocking operations asynchronously, your application may still not serve as expected. This happens if there is a code outside the callback that relies on the code within the callback to run first. For example, consider the following code:

 const fs = require ( 'fs' );
 fs . readFile ( '/file.txt' , ( err , data ) => {
 // perform actions on file content
 });
 fs . unlinkSync ( '/file.txt' );

In the above example,
unlinkSync
 function may run before the callback, which will delete the file before the desired actions on the file content is done. Such race conditions can also affect the security of your application. An example would be a scenario where authentication is performed in a callback and authenticated actions are run synchronously. In order to eliminate such race conditions, you can write all operations that rely on each other in a single non-blocking function. By doing so, you can guarantee that all operations are executed in the correct order. For example, above code example can be written in a non-blocking way as follows:

 const fs = require ( 'fs' );
 fs . readFile ( '/file.txt' , ( err , data ) => {
 // perform actions on file content
 fs . unlink ( '/file.txt' , ( err ) => {
 if ( err ) throw err ;
 });
 });

In the above code, call to unlink the file and other file operations are within the same callback. This provides the correct order of operations.

 Perform input validation &para;

Input validation is a crucial part of application security. Input validation failures can result in many types of application attacks. These include SQL Injection, Cross-Site Scripting, Command Injection, Local/Remote File Inclusion, Denial of Service, Directory Traversal, LDAP Injection and many other injection attacks. In order to avoid these attacks, input to your application should be sanitized first. The best input validation technique is to use a list of accepted inputs. However, if this is not possible, input should be first checked against expected input scheme and dangerous inputs should be escaped. In order to ease input validation in Node.js applications, there are some modules like validator and express-mongo-sanitize .
For detailed information on input validation, please refer to Input Validation Cheat Sheet .

JavaScript is a dynamic language and depending on how the framework parses a URL, the data seen by the application code can take many forms. Here are some examples after parsing a query string in express.js:

 URL
 Content of request.query.foo in code

?foo=bar

'bar'
 (string)

?foo=bar&foo=baz

['bar', 'baz']
 (array of string)

?foo[]=bar

['bar']
 (array of string)

?foo[]=bar&foo[]=baz

['bar', 'baz']
 (array of string)

?foo[bar]=baz

{ bar : 'baz' }
 (object with a key)

?foo[]baz=bar

['bar']
 (array of string - postfix is lost)

?foo[][baz]=bar

[ { baz: 'bar' } ]
 (array of object)

?foo[bar][baz]=bar

{ foo: { bar: { baz: 'bar' } } }
 (object tree)

?foo[10]=bar&foo[9]=baz

[ 'baz', 'bar' ]
 (array of string - notice order)

?foo[toString]=bar

{}
 (object where calling
toString()
 will fail)

 Perform output escaping &para;

In addition to input validation, you should escape all HTML and JavaScript content shown to users via application in order to prevent cross-site scripting (XSS) attacks. You can use escape-html or node-esapi libraries to perform output escaping.

 Perform application activity logging &para;

Logging application activity is an encouraged good practice. It makes it easier to debug any errors encountered during application runtime. It is also useful for security concerns, since it can be used during incident response. In addition, these logs can be used to feed Intrusion Detection/Prevention Systems (IDS/IPS). In Node.js, there are modules such as Winston , Bunyan , or Pino to perform application activity logging. These modules enable streaming and querying logs, and they provide a way to handle uncaught exceptions.

With the following code, you can log application activities in both console and a desired log file:

 const logger = new ( Winston . Logger ) ({
 transports : [
 new ( winston . transports . Console )(),
 new ( winston . transports . File )({ filename : 'application.log' })
 ],
 level : 'verbose'
 });

You can provide different transports so that you can save errors to a separate log file and general application logs to a different log file. Additional information on security logging can be found in Logging Cheat Sheet .

 Monitor the event loop &para;

When your application server is under heavy network traffic, it may not be able to serve its users. This is essentially a type of Denial of Service (DoS) attack. The toobusy-js module allows you to monitor the event loop. It keeps track of the response time, and when it goes beyond a certain threshold, this module can indicate your server is too busy. In that case, you can stop processing incoming requests and send them
503 Server Too Busy
 message so that your application stay responsive. Example use of the toobusy-js module is shown here:

 const toobusy = require ( 'toobusy-js' );
 const express = require ( 'express' );
 const app = express ();
 app . use ( function ( req , res , next ) {
 if ( toobusy ()) {
 // log if you see necessary
 res . status ( 503 ). send ( "Server Too Busy" );
 } else {
 next ();
 }
 });

 Take precautions against brute-forcing &para;

 Brute-forcing is a common threat to all web applications. Attackers can use brute-forcing as a password guessing attack to obtain account passwords. Therefore, application developers should take precautions against brute-force attacks especially in login pages. Node.js has several modules available for this purpose. Express-bouncer , express-brute and rate-limiter are just some examples. Based on your needs and requirements, you should choose one or more of these modules and use accordingly. Express-bouncer and express-brute modules work similarly. They increase the delay for each failed request and can be arranged for a specific route. These modules can be used as follows:

 const bouncer = require ( 'express-bouncer' );
 bouncer . whitelist . push ( '127.0.0.1' ); // allow an IP address
 // give a custom error message
 bouncer . blocked = function ( req , res , next , remaining ) {
 res . status ( 429 ). send ( "Too many requests have been made. Please wait " + remaining / 1000 + " seconds." );
 };
 // route to protect
 app . post ( "/login" , bouncer . block , function ( req , res ) {
 if ( LoginFailed ){ }
 else {
 bouncer . reset ( req );
 }
 });

 const ExpressBrute = require ( 'express-brute' );

 const store = new ExpressBrute . MemoryStore (); // stores state locally, don't use this in production
 const bruteforce = new ExpressBrute ( store );

 app . post ( '/auth' ,
 bruteforce . prevent , // error 429 if we hit this route too often
 function ( req , res , next ) {
 res . send ( 'Success!' );
 }
 );

Apart from express-bouncer and express-brute , the rate-limiter module can also help to prevent brute-forcing attacks. It enables specifying how many requests a specific IP address can make during a specified time period.

 const limiter = new RateLimiter ();
 limiter . addLimit ( '/login' , 'GET' , 5 , 500 ); // login page can be requested 5 times at max within 500 seconds

 CAPTCHA usage is also another common mechanism used against brute-forcing. There are modules developed for Node.js CAPTCHAs. A common module used in Node.js applications is svg-captcha . It can be used as follows:

 const svgCaptcha = require ( 'svg-captcha' );
 app . get ( '/captcha' , function ( req , res ) {
 const captcha = svgCaptcha . create ();
 req . session . captcha = captcha . text ;
 res . type ( 'svg' );
 res . status ( 200 ). send ( captcha . data );
 });

 Account lockout is a recommended solution to keep attackers away from your valid users. Account lockout is possible with many modules like mongoose . You can refer to this blog post to see how account lockout is implemented in mongoose.

 Use Anti-CSRF tokens &para;

 Cross-Site Request Forgery (CSRF) aims to perform authorized actions on behalf of an authenticated user, while the user is unaware of this action. CSRF attacks are generally performed for state-changing requests like changing a password, adding users or placing orders. Csurf is an express middleware that has been used to mitigate CSRF attacks. But a security hole in this package has been recently discovered. The team behind the package has not fixed the discovered vulnerability and they have marked the package as deprecated, recommending using any other CSRF protection package.

For detailed information on cross-site request forgery (CSRF) attacks and prevention methods, you can refer to Cross-Site Request Forgery Prevention .

 Remove unnecessary routes &para;

A web application should not contain any page that is not used by users, as it may increase the attack surface of the application. Therefore, all unused API routes should be disabled in Node.js applications. This occurs especially in frameworks like Sails and Feathers , as they automatically generate REST API endpoints. For example, in Sails , if a URL does not match a custom route, it may match one of the automatic routes and still generate a response. This situation may lead to results ranging from information leakage to arbitrary command execution. Therefore, before using such frameworks and modules, it is important to know the routes they automatically generate and remove or disable these routes.

 Prevent HTTP Parameter Pollution &para;

 HTTP Parameter Pollution(HPP) is an attack in which attackers send multiple HTTP parameters with the same name and this causes your application to interpret them unpredictably. When multiple parameter values are sent, Express populates them in an array. In order to solve this issue, you can use hpp module. When used, this module will ignore all values submitted for a parameter in
req.query
 and/or
req.body
 and just select the last parameter value submitted. You can use it as follows:

 const hpp = require ( 'hpp' );
 app . use ( hpp ());

 Only return what is necessary &para;

Information about the users of an application is among the most critical information about the application. User tables generally include fields like ID, username, full name, email address, birth date, password and in some cases social security numbers. Therefore, when querying and using user objects, you need to return only needed fields as it may be vulnerable to personal information disclosure. This is also correct for other objects stored on the database. If you just need a certain field of an object, you should only return the specific fields required. As an example, you can use a function like the following whenever you need to get information on a user. By doing so, you can only return the fields that are needed for your specific operation. In other words, if you only need to list names of the users available, you are not returning their email addresses or credit card numbers in addition to their full names.

 exports . sanitizeUser = function ( user ) {
 return {
 id : user . id ,
 username : user . username ,
 fullName : user . fullName
 };
 };

 Use object property descriptors &para;

Object properties include three hidden attributes:
writable
 (if false, property value cannot be changed),
enumerable
 (if false, property cannot be used in for loops) and
configurable
 (if false, property cannot be deleted). When defining an object property through assignment, these three hidden attributes are set to true by default. These properties can be set as follows:

 const o = {};
 Object . defineProperty ( o , "a" , {
 writable : true ,
 enumerable : true ,
 configurable : true ,
 value : "A"
 });

Apart from these, there are some special functions for object attributes.
Object.preventExtensions()
 prevents new properties from being added to the object.

 Use access control lists &para;

Authorization prevents users from acting outside of their intended permissions. In order to do so, users and their roles should be determined with consideration of the principle of least privilege. Each user role should only have access to the resources they must use. For your Node.js applications, you can use the acl module to provide ACL (access control list) implementation. With this module, you can create roles and assign users to these roles.

Handle uncaughtException &para;

Node.js behavior for uncaught exceptions is to print current stack trace and then terminate the thread. However, Node.js allows customization of this behavior. It provides a global object named process that is available to all Node.js applications. It is an EventEmitter object and in case of an uncaught exception, uncaughtException event is emitted and it is brought up to the main event loop. In order to provide a custom behavior for uncaught exceptions, you can bind to this event. However, resuming the application after such an uncaught exception can lead to further problems. Therefore, if you do not want to miss any uncaught exception, you should bind to uncaughtException event and cleanup any allocated resources like file descriptors, handles and similar before shutting down the process. Resuming the application is strongly discouraged as the application will be in an unknown state. It is important to note that when displaying error messages to the user in case of an uncaught exception, detailed information like stack traces should not be revealed to the user. Instead, custom error messages should be shown to the users in order not to cause any information leakage.

 process . on ( "uncaughtException" , function ( err ) {
 // clean up allocated resources
 // log necessary error details to log files
 process . exit (); // exit the process to avoid unknown state
 });

 Listen to errors when using EventEmitter &para;

When using EventEmitter, errors can occur anywhere in the event chain. Normally, if an error occurs in an EventEmitter object, an error event that has an Error object as an argument is called. However, if there are no attached listeners to that error event, the Error object that is sent as an argument is thrown and becomes an uncaught exception. In short, if you do not handle errors within an EventEmitter object properly, these unhandled errors may crash your application. Therefore, you should always listen to error events when using EventEmitter objects.

 const events = require ( 'events' );
 const myEventEmitter = function (){
 events . EventEmitter . call ( this );
 }
 require ( 'util' ). inherits ( myEventEmitter , events . EventEmitter );
 myEventEmitter . prototype . someFunction = function ( param1 , param2 ) {
 //in case of an error
 this . emit ( 'error' , err );
 }
 const emitter = new myEventEmitter ();
 emitter . on ( 'error' , function ( err ){
 //Perform necessary error handling here
 });

 Handle errors in asynchronous calls &para;

Errors that occur within asynchronous callbacks are easy to miss. Therefore, as a general principle first argument to the asynchronous calls should be an Error object. Also, express routes handle errors itself, but it should be always remembered that errors occurred in asynchronous calls made within express routes are not handled, unless an Error object is sent as a first argument.

Errors in these callbacks can be propagated as many times as possible. Each callback that the error has been propagated to can ignore, handle or propagate the error.

Set cookie flags appropriately &para;

Generally, session information is sent using cookies in web applications. However, improper use of HTTP cookies can render an application to several session management vulnerabilities. Some flags can be set for each cookie to prevent these kinds of attacks.
httpOnly
,
Secure
 and
SameSite
 flags are very important for session cookies.
httpOnly
 flag prevents the cookie from being accessed by client-side JavaScript. This is an effective counter-measure for XSS attacks.
Secure
 flag lets the cookie to be sent only if the communication is over HTTPS.
SameSite
 flag can prevent cookies from being sent in cross-site requests that helps protect against Cross-Site Request Forgery (CSRF) attacks. Apart from these, there are other flags like domain, path and expires. Setting these flags appropriately is encouraged, but they are mostly related to cookie scope not the cookie security. Sample usage of these flags is given in the following example:

 const session = require ( 'express-session' );
 app . use ( session ({
 secret : 'your-secret-key' ,
 name : 'cookieName' ,
 cookie : { secure : true , httpOnly : true , path : '/user' , sameSite : true }
 }));

 Use appropriate security headers &para;

There are several HTTP security headers that can help you prevent some common attack vectors.
The helmet package can help to set those headers:

 const express = require ( "express" );
 const helmet = require ( "helmet" );

 const app = express ();

 app . use ( helmet ()); // Add various HTTP headers

The top-level
helmet
 function is a wrapper around 14 smaller middlewares.
Below is a list of HTTP security headers covered by
helmet
 middlewares:

 Strict-Transport-Security : HTTP Strict Transport Security (HSTS) dictates browsers that the application can only be accessed via HTTPS connections. In order to use it in your application, add the following codes:

 app . use ( helmet . hsts ()); // default configuration
 app . use (
 helmet . hsts ({
 maxAge : 123456 ,
 includeSubDomains : false ,
 })
 ); // custom configuration

 X-Frame-Options : determines if a page can be loaded via a
<frame>
 or an
<iframe>
 element. Allowing the page to be framed may result in Clickjacking attacks.

 app . use ( helmet . frameguard ()); // default behavior (SAMEORIGIN)

 X-XSS-Protection : stops pages from loading when they detect reflected cross-site scripting (XSS) attacks. This header has been deprecated by modern browsers and its use can introduce additional security issues on the client side. As such, it is recommended to set the header as X-XSS-Protection: 0 in order to disable the XSS Auditor, and not allow it to take the default behavior of the browser handling the response.

 app . use ( helmet . xssFilter ()); // sets "X-XSS-Protection: 0"

For moderns browsers, it is recommended to implement a strong Content-Security-Policy policy, as detailed in the next section.

 Content-Security-Policy : Content Security Policy is developed to reduce the risk of attacks like Cross-Site Scripting (XSS) and Clickjacking . It allows content from a list that you decide. It has several directives each of which prohibits loading specific type of a content. You can refer to Content Security Policy Cheat Sheet for detailed explanation of each directive and how to use it. You can implement these settings in your application as follows:

 app . use (
 helmet . contentSecurityPolicy ({
 // the following directives will be merged into the default helmet CSP policy
 directives : {
 defaultSrc : [ "'self'" ], // default value for all directives that are absent
 scriptSrc : [ "'self'" ], // helps prevent XSS attacks
 frameAncestors : [ "'none'" ], // helps prevent Clickjacking attacks
 imgSrc : [ "'self'" , "'http://imgexample.com'" ],
 styleSrc : [ "'none'" ]
 }
 })
 );

As this middleware performs very little validation, it is recommended to rely on CSP checkers like CSP Evaluator instead.

 X-Content-Type-Options : Even if the server sets a valid
Content-Type
 header in the response, browsers may try to sniff the MIME type of the requested resource. This header is a way to stop this behavior and tell the browser not to change MIME types specified in
Content-Type
 header. It can be configured in the following way:

 app . use ( helmet . noSniff ());

 Cache-Control and Pragma : Cache-Control header can be used to prevent browsers from caching the given responses. This should be done for pages that contain sensitive information about either the user or the application. However, disabling caching for pages that do not contain sensitive information may seriously affect the performance of the application. Therefore, caching should only be disabled for pages that return sensitive information. Appropriate caching controls and headers can be set easily using the nocache package:

 const nocache = require ( "nocache" );

 app . use ( nocache ());

The above code sets Cache-Control, Surrogate-Control, Pragma and Expires headers accordingly.

 X-Download-Options: This header prevents Internet Explorer from executing downloaded files in the site's context. This is achieved with noopen directive. You can do so with the following piece of code:

 app . use ( helmet . ieNoOpen ());

 X-Powered-By: X-Powered-By header is used to inform what technology is used in the server side. This is an unnecessary header causing information leakage, so it should be removed from your application. To do so, you can use the
hidePoweredBy
 as follows:

 app . use ( helmet . hidePoweredBy ());

Also, you can lie about the technologies used with this header. For example, even if your application does not use PHP, you can set X-Powered-By header to seem so.

 app . use ( helmet . hidePoweredBy ({ setTo : 'PHP 4.2.0' }));

